INSERT INTO listings (external_id,source,url,title,deal_type,price,currency,area_m2,rooms,floor,total_floors,year_built,furnished,address,city,latitude,longitude,images,description,is_active) VALUES ('7308070','index-hr','https://www.index.hr/oglasi/nekretnine/prodaja-stanova/oglas/stan-novi-zagreb-zapad-blato-36m2-2-sobni-i-parking-mjesto/7308070','Stan Novi Zagreb - Zapad (Blato), 36m2, 2-sobni i parking mjesto','sale',180000.0,'EUR',36.0,2,2,1,2026,false,'Novi Zagreb - Zapad, Blato','Zagreb',45.7620089,15.9190856,'{"https://www.index.hr/oglasi/api/image/direct/702e3817-0953-41e0-eba7-08ddd98f02bb/46ecfde2-fbba-468f-8e1a-89dab9e6cfcc.jpg","https://www.index.hr/oglasi/api/image/direct/702e3817-0953-41e0-eba7-08ddd98f02bb/6cea2459-61ad-47d0-b220-b2f2121cfedb.jpg","https://www.index.hr/oglasi/api/image/direct/702e3817-0953-41e0-eba7-08ddd98f02bb/d63558df-72ce-42a2-974a-38a4c6b5adfd.jpg","https://www.index.hr/oglasi/api/image/direct/702e3817-0953-41e0-eba7-08ddd98f02bb/7f474fd2-12bb-4cb5-85d0-81d81c60ccfd.jpg","https://www.index.hr/oglasi/api/image/direct/702e3817-0953-41e0-eba7-08ddd98f02bb/d5a8513d-8712-4ff6-9ef1-b8b4c63bc6fb.jpg"}','Prodaje se moderan dvosoban stan u visokom prizemlju kvalitetne novogradnje, čiji se završetak očekuje uskoro, s planiranim useljenjem u lipnju 2026. godine. Stan ukupne površine 37 m² idealan je za samce, parove ili kao investicija za najam.

Sastoji se od ulaznog hodnika, dnevnog boravka s kuhinjom i blagovaonicom, jedne spavaće sobe te kupaonice. Iz dnevnog boravka omogućen je izlaz na balkon, koji pruža dodatni prostor za opuštanje.

Uz stan dolazi i vanjsko natkriveno parkirno mjesto.

Stan se nalazi u energetski učinkovitoj zgradi s A+ certifikatom, što osigurava niske režijske troškove i ugodan boravak tijekom cijele godine.

Oprema i materijali su vrhunske kvalitete:

Protuprovalna i protupožarna ulazna vrata renomiranog proizvođača DIERRE, s visokokvalitetnim sigurnosnim cilindrom
Kvalitetna unutarnja stolarija u bijeloj boji s dovratnicima visine 210 cm
Višeslojni gotovi hrastov parket 1. klase u sobama, dnevnom boravku i hodnicima
Keramičke pločice u kuhinji i kupaonici, te protuklizne pločice na balkonu
Zidovi strojno žbukani, gletani i ličeni, s kvalitetnom izvedbom i dobrom zvučnom izolacijom


Grijanje i hlađenje je putem dizalice topline, uz podno grijanje kroz cijeli stan i digitalni termostat za jednostavno upravljanje temperaturom.

Ova nekretnina predstavlja odličan spoj kvalitetne gradnje, funkcionalnog rasporeda i moderne opreme. Za više informacija, slobodno nas kontaktirajte.',true) ON CONFLICT (source,external_id) DO NOTHING;
