INSERT INTO listings (external_id,source,url,title,deal_type,price,currency,area_m2,rooms,floor,total_floors,year_built,furnished,address,city,latitude,longitude,images,description,is_active) VALUES ('7307037','index-hr','https://www.index.hr/oglasi/nekretnine/prodaja-stanova/oglas/jankomir-ekskluzivna-gradnja-cetverosoban-stan-od-77-00-m2-novogr/7307037','Jankomir, ekskluzivna gradnja, četverosoban stan od 77.00 m2, novogr.','sale',285348.0,'EUR',77.0,4,4,1,NULL,NULL,'Stenjevec, Jankomir','Zagreb',45.80695,15.85834,'{"https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/d427fcd6-93d8-4624-92f5-ff835c684dc1.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/2e023dcc-e897-42de-b686-23fb401cbd91.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/dbe01ad6-200c-4113-bdce-a8af289fa570.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/96f8db79-d735-43e2-81fe-41ce3ed2dc67.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/773c53ed-4853-4c65-89a4-a14aa81ec09c.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/010f20a5-5bdb-4d58-a211-fd52ec7b15a2.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/4d8f5594-8529-418a-bbf9-7a24521c0e95.jpg","https://www.index.hr/oglasi/api/image/direct/77f49f84-2041-4148-84a1-fdd20b5797ad/df30f0be-6115-4d91-b3db-8f7eebc3bef6.jpg"}','EKSKLUZIVNA NOVOGRADNJA, 4-soban stan 77,33 m2 vrhunska gradnja, privatnost i energetska učinkovitost.
 
 - U ponudi je pažljivo projektiran četverosoban stan u modernoj urbanoj vili s ukupno svega 9 stanova, smještenoj u mirnom dijelu Jankomira.
 Ova nekretnina predstavlja spoj suvremene arhitekture, visokih građevinskih standarda i dugoročne vrijednosti, namijenjena kupcima koji ne traže kompromis.
 
 * ARHITEKTURA I KVALITETA GRADNJE
 - Projekt je izveden u armirano-betonskoj konstrukciji, što osigurava maksimalnu stabilnost, trajnost i vrhunsku zvučnu izolaciju.
 - Poseban naglasak stavljen je na: višeslojnu toplinsku zaštitu (fasada 15 cm, krov 20 cm) troslojnu stolariju s RAL montažom napredne sustave izolacije i niskošumne instalacije
 - Rezultat je mir, energetska učinkovitost i dugoročno očuvanje vrijednosti nekretnine.
 
 * KOMFOR I TEHNOLOGIJA
 - Stan je opremljen sustavima koji podižu kvalitetu svakodnevnog života: podno grijanje u svim prostorijama putem dizalice topline, individualni termostati u svakoj prostoriji, klimatizacija prostora, video portafon u boji, električne ALU rolete i komarnici, protuprovalna i protupožarna ulazna vrata s dodatnom zvučnom izolacijom.
 - Visina stropa od 265 cm dodatno naglašava osjećaj prostora i svjetline.
 
 * INTERIJER I MATERIJALI
 - Unutarnje uređenje prati visoke standarde stanovanja: hrastov parket, keramika I klase, suvremeno opremljene kupaonice (walk-in ili kada po izboru), mogućnost personalizacije materijala u fazi gradnje.
 - Svaki detalj osmišljen je s ciljem funkcionalnosti, estetike i trajnosti.
 
 * KONCEPT ŽIVOTA
 - Manji stambeni projekt s ukupno 9 stanova osigurava: visoku razinu privatnosti, mirno i sigurno okruženje, osjećaj “zatvorene zajednice” bez prenapučenosti.
 - Lift, spremišta i uređeni okoliš dodatno podižu kvalitetu stanovanja.
 
 * LOKACIJA
 - Smješten u mirnoj ulici, s izvrsnom prometnom povezanošću i brzom dostupnošću svih ključnih sadržaja, stan omogućuje idealan balans između privatnosti i urbanog života.
 
 * INVESTICIJSKA VRIJEDNOST
 - Energetski razred A+ i suvremeni sustavi grijanja značajno smanjuju troškove života, dok kvalitetna gradnja i lokacija osiguravaju dugoročnu vrijednost i likvidnost nekretnine.
 
 * ZAVRŠNA PORUKA
 - Ova nekretnina nije samo stan, već dugoročno siguran izbor za kvalitetan život ili investiciju.
 
 - Nekretnine je u izgradnji - završetak srpanj 2027.g.
 
 - Četverosoban stan na drugom od ukupno tri kata.
 - Stan 77,33m2
 - VPM 12,50m2 (3,13m2)
 - SPR od 3,29 do 4,05m2
 
 - Cijena stana 77,33m2 X 3.690€/m2 = 285.348€
 
 - Vjerujemo Vam i smatramo da je danas teško pronaći nekretninu s idealnim omjerom, uloženog/dobivenog, dajte si šansu, pogledajte ovaj projekat, bit ćete oduševljeni.
 
 - Kupac ne plaća agencijsku proviziju.
 - Obilasci lokacije, projekta i konkretno stana, termin prema dogovoru.
 
 - Raspitajte se o ovoj ATRAKTIVNOJ nekretnini:
 
