INSERT INTO listings (external_id,source,url,title,deal_type,price,currency,area_m2,rooms,floor,total_floors,year_built,furnished,address,city,latitude,longitude,images,description,is_active) VALUES ('7306418','index-hr','https://www.index.hr/oglasi/nekretnine/prodaja-stanova/oglas/zagreb-britanski-trg-4s-stan-za-renovaciju-147-m/7306418','Zagreb, Britanski trg, 4s stan za renovaciju, 147 m²','sale',597360.0,'EUR',147.0,4,5,1,NULL,NULL,'Gornji Grad - Medveščak, Britanac','Zagreb',45.8133975,15.9646556,NULL,'Prodaje se prostrani četverosobni stan površine 147 m² smješten na trećem katu stambene zgrade iz 1895. godine, na jednoj od najprestižnijih lokacija u Zagrebu, Britanskom trgu.

Stan se sastoji od ulaznog hodnika sa stepeništem, prostranog dnevnog boravka, tri velike spavaće sobe, kuhinje, kupaonice i ostave. Orijentacija istok–zapad osigurava obilje prirodnog svjetla tijekom cijelog dana.

Nekretnina se nalazi u fazi za kompletnu adaptaciju, što budućem vlasniku pruža iznimnu priliku da prostor uredi potpuno prema vlastitim željama i potrebama. 

Posebnu vrijednost ovoj nekretnini daje zajednička krovna terasa zgrade kojoj direktan pristup ima isključivo ovaj stan, gotovo privatni vanjski prostor u samom centru grada, prava rijetkost na tržištu. Uz stan dolazi i spremište u podrumu zgrade.

Postoji i mogućnost kupnje susjednog stana (112 m²), čime bi se dobila impozantna stambena cjelina veća od 260 m² na jednoj etaži jedinstvena prilika za luksuzni penthouse tip stana ili reprezentativni gradski dom u centru Zagreba.

Za stan postoji pravomoćna građevinska dozvola, što dodatno povećava dugoročnu vrijednost nekretnine.

Stan se nalazi u neposrednoj blizini restorana, kafića, trgovina, kulturnih sadržaja i javnog prijevoza.

Ako je za ovu nekretninu na nekoj drugoj web stranici objavljena niža cijena, ista vrijedi i kod nas. Za sva dodatna pitanja i razgled nekretnine stojimo Vam na raspolaganju.

